const express = require('express');
const router = express.Router();
const db = require('./db'); // assuming a database connection is established here

// Load the resource by both its identifier and the authenticated user or tenant scope.
router.get('/documents', async (req, res) => {
  try {
    const documents = await db.getDocumentByCompanyId(req.user.companyId);
    res.json(documents);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error fetching documents' });
  }
});

// Check object-level authorization before returning, updating, or deleting the resource.
router.get('/documents/:id', async (req, res) => {
  try {
    const document = await db.getDocumentById(req.params.id);
    if (!document || document.companyId !== req.user.companyId) {
      return res.status(404).json({ message: 'Document not found or unauthorized' });
    }
    res.json(document);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error fetching document' });
  }
});

// Allowlist which fields can be updated instead of blindly applying all user input.
router.patch('/documents/:id', async (req, res) => {
  try {
    const allowedFields = ['title', 'content'];
    const updates = {};
    for (const field in req.body) {
      if (allowedFields.includes(field)) {
        updates[field] = req.body[field];
      }
    }
    const document = await db.getDocumentById(req.params.id);
    if (!document || document.companyId !== req.user.companyId) {
      return res.status(404).json({ message: 'Document not found or unauthorized' });
    }
    const updatedDocument = await db.updateDocument(document.id, updates);
    res.json(updatedDocument);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error updating document' });
  }
});

// Enforce role checks for admin-only functionality on the server side.
router.get('/documents/:id/admin', async (req, res) => {
  try {
    const document = await db.getDocumentById(req.params.id);
    if (!document || document.companyId !== req.user.companyId) {
      return res.status(404).json({ message: 'Document not found or unauthorized' });
    }
    if (req.user.role === 'admin') {
      // admin-only functionality
      const adminDocuments = await db.getAdminDocuments(req.user.companyId);
      res.json(adminDocuments);
    } else {
      return res.status(403).json({ message: 'Forbidden' });
    }
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Error fetching admin documents' });
  }
});

module.exports = router;